   389вҶ’
   390вҶ’### MOMENTUM ALGORITHM
   391вҶ’
   392вҶ’```typescript
   393вҶ’const startMomentum = useCallback(() => {
   394вҶ’  const { vx, vy } = calculateAverageVelocity();
   395вҶ’
   396вҶ’  canvasStore.dispatch(canvasActions.viewport.startMomentum({
   397вҶ’    velocityX: vx * 16, // Convert to world units per frame
   398вҶ’    velocityY: vy * 16,
   399вҶ’  }));
   400вҶ’
   401вҶ’  const animate = () => {
   402вҶ’    const state = canvasStore.getState();
   403вҶ’    const { velocityX, velocityY, isActive } = state.viewport.momentum;
   404вҶ’
   405вҶ’    if (!isActive) return;
   406вҶ’
   407вҶ’    // Apply friction
   408вҶ’    const newVelX = velocityX * MOMENTUM_FRICTION;
   409вҶ’    const newVelY = velocityY * MOMENTUM_FRICTION;
   410вҶ’
   411вҶ’    // Check velocity threshold
   412вҶ’    if (Math.abs(newVelX) < MOMENTUM_MIN_VELOCITY &&
   413вҶ’        Math.abs(newVelY) < MOMENTUM_MIN_VELOCITY) {
   414вҶ’      canvasStore.dispatch(canvasActions.viewport.stopMomentum());
   415вҶ’      return;
   416вҶ’    }
   417вҶ’
   418вҶ’    // Update camera position
   419вҶ’    const newCamera = clampCameraToWorld(
   420вҶ’      camera.x + newVelX,
   421вҶ’      camera.y + newVelY,
   422вҶ’      zoom
   423вҶ’    );
   424вҶ’
   425вҶ’    canvasStore.dispatch(canvasActions.viewport.updateMomentum({
   426вҶ’      velocityX: newVelX,
   427вҶ’      velocityY: newVelY,
   428вҶ’      camera: newCamera,
   429вҶ’    }));
   430вҶ’
   431вҶ’    requestAnimationFrame(animate);
   432вҶ’  };
   433вҶ’
   434вҶ’  requestAnimationFrame(animate);
   435вҶ’}, []);
   436вҶ’```
   437вҶ’
   438вҶ’### EASING FUNCTIONS
   439вҶ’
   440вҶ’```typescript
   441вҶ’const Easing = {
   442вҶ’  quadOut: (t: number) => t * (2 - t),
   443вҶ’  cubicOut: (t: number) => 1 - Math.pow(1 - t, 3),
   444вҶ’};
