   459вҶ’
   460вҶ’## 5. Performance Optimizations
   461вҶ’
   462вҶ’### 5.1 RBush Spatial Index
   463вҶ’
   464вҶ’**File:** `apps/canvas/src/spatial/RBushSpatialIndex.ts`
   465вҶ’
   466вҶ’```typescript
   467вҶ’export class RBushSpatialIndex implements ISpatialIndex {
   468вҶ’  private tree: RBush<RBushItem>;
   469вҶ’  private itemsById: Map<string, RBushItem> = new Map();
   470вҶ’
   471вҶ’  load(items: SpatialItem[]): void {
   472вҶ’    const startTime = performance.now();
   473вҶ’
   474вҶ’    this.tree.clear();
   475вҶ’    this.itemsById.clear();
   476вҶ’
   477вҶ’    for (const item of items) {
   478вҶ’      this.itemsById.set(item.id, item as RBushItem);
   479вҶ’    }
   480вҶ’
   481вҶ’    this.tree.load(items as RBushItem[]); // Bulk load is O(n log n)
   482вҶ’
   483вҶ’    // Performance: ~0.5ms for 60k items
   484вҶ’  }
   485вҶ’
   486вҶ’  queryViewport(bounds: ViewportBounds): string[] {
   487вҶ’    // O(log n + k) where k = result count
   488вҶ’    const results = this.tree.search({
   489вҶ’      minX: bounds.minX,
   490вҶ’      minY: bounds.minY,
   491вҶ’      maxX: bounds.maxX,
   492вҶ’      maxY: bounds.maxY,
   493вҶ’    });
   494вҶ’
   495вҶ’    return results.map(item => item.id);
   496вҶ’  }
   497вҶ’
   498вҶ’  queryNearest(x: number, y: number, maxDistance?: number): SpatialQueryResult | null {
   499вҶ’    // Expanding radius search
   500вҶ’    let radius = 50;
   501вҶ’    while (radius <= maxRadius && nearest === null) {
   502вҶ’      const candidates = this.tree.search({
   503вҶ’        minX: x - radius,
   504вҶ’        minY: y - radius,
   505вҶ’        maxX: x + radius,
   506вҶ’        maxY: y + radius,
   507вҶ’      });
   508вҶ’
   509вҶ’      for (const item of candidates) {
   510вҶ’        const dist = distanceToCenter(x, y, item);
   511вҶ’        if (dist < minDist && dist <= maxRadius) {
   512вҶ’          minDist = dist;
   513вҶ’          nearest = { id: item.id, distance: dist };
   514вҶ’        }
   515вҶ’      }
   516вҶ’
   517вҶ’      radius *= 2;
   518вҶ’    }
   519вҶ’
   520вҶ’    return nearest;
   521вҶ’  }
   522вҶ’}
