## Data Generation

### Mock Data Generator

Implementation: `apps/canvas/src/data/generator.ts`

The generator creates:

1. **50 Trains** with unique IDs (TRAIN-001 to TRAIN-050)
2. **10 Years of Tasks** (~10-12 tasks per train per year)
3. **~5% Conflict Rate** (hasConflict flag for testing)

### Generation Algorithm

```typescript
function generateData(meta: DatasetMeta): GeneratedData {
  const trains = generateTrains(meta.trainCount);
  const tasks = generateTasks(trains, meta);

  return { trains, tasks, meta };
}

function generateTrains(count: number): Train[] {
  return Array.from({ length: count }, (_, i) => ({
    id: `TRAIN-${String(i + 1).padStart(3, '0')}`,
    name: `Train ${i + 1}`,
    assetType: i < 30 ? 'ALSTOM' : 'KINKI',
  }));
}

function generateTasks(trains: Train[], meta: DatasetMeta): Task[] {
  const tasks: Task[] = [];
  const types: TaskType[] = ['maintenance', 'overhaul', 'inspection'];

  trains.forEach((train) => {
    for (let year = 0; year < meta.years; year++) {
      const tasksPerYear = 8 + Math.floor(Math.random() * 5);
      for (let t = 0; t < tasksPerYear; t++) {
        const dayOffset = year * 365 + Math.floor(Math.random() * 360);
        const duration = 2 + Math.floor(Math.random() * 10);
        const startDate = addDays(meta.startDate, dayOffset);
        const endDate = addDays(startDate, duration);

        tasks.push({
          id: `${train.id}-${year}-${t}`,
          trainId: train.id,
          startDate: formatISO(startDate),
          endDate: formatISO(endDate),
          type: types[Math.floor(Math.random() * types.length)],
          hasConflict: Math.random() < 0.05,  // 5% conflict rate
        });
      }
    }
  });

  return tasks;
}
```

### Transform to Render Data

```typescript
function prepareRenderData(
  data: GeneratedData
): { trains: Train[]; tasks: TaskRender[] } {
  const trainIndexMap = new Map(
    data.trains.map((t, i) => [t.id, i])
  );
  const startDate = new Date(data.meta.startDate);

  const tasks = data.tasks.map(task => ({
    id: task.id,
    trainIndex: trainIndexMap.get(task.trainId)!,
    startDay: daysBetween(startDate, new Date(task.startDate)),
    duration: daysBetween(new Date(task.startDate), new Date(task.endDate)),
    color: TYPE_TO_COLOR[task.type],
    hasConflict: task.hasConflict,
    type: task.type,
  }));

  return { trains: data.trains, tasks };
}
```

